1	// rfq-grid.jsx — reusable data-grid renderer for the RFQ canvas.
2	// Props let each artboard show a different state (current vs polished,
3	// density, frozen columns, collapsed/expanded scenario groups).
4	// Exports <RfqGrid> to window. Depends on rfq-data.jsx.
5	
6	(function () {
7	  const { RFQ, SCENARIO, money, pct, qty, Thumb, STEPS } = window;
8	  const SEAM_LINE = '1.5px solid #d4dae3';
9	
10	  // One-time grid CSS (rg- prefixed).
11	  if (!document.getElementById('rg-styles')) {
12	    const s = document.createElement('style');
13	    s.id = 'rg-styles';
14	    s.textContent = `
15	    .rg-scroll{overflow-x:auto;overflow-y:hidden;width:100%}
16	    .rg-table{border-collapse:separate;border-spacing:0;font-family:${RFQ.font};table-layout:fixed}
17	    .rg-table th,.rg-table td{box-sizing:border-box;text-align:left;overflow:hidden;white-space:nowrap;text-overflow:ellipsis}
18	    .rg-num{font-variant-numeric:tabular-nums;text-align:right;font-feature-settings:"tnum"}
19	    .rg-pin{position:sticky;background:inherit;z-index:2}
20	    .rg-pinshadow{box-shadow:6px 0 8px -6px rgba(20,30,50,.18)}
21	    `;
22	    document.head.appendChild(s);
23	  }
24	
25	  // Flatten a segment list into header rows + leaf columns.
26	  // segment = plain col descriptor  OR  { group:{fam,term,collapsed} }
27	  function flatten(segments) {
28	    const leaves = [];
29	    const top = [];     // top header cells (bands / tall labels)
30	    const bottom = [];   // second-row header cells (scenario sub-labels)
31	    let hasBand = segments.some((s) => s.group && !s.group.collapsed);
32	    segments.forEach((seg, i) => {
33	      if (seg.group) {
34	        const { fam, term, collapsed } = seg.group;
35	        const sc = SCENARIO[fam];
36	        if (collapsed) {
37	          const col = { key: `${fam}_${term.toLowerCase()}_sales`, label: 'Sales', w: 92, type: 'money', align: 'right', fam, term, metric: 'sales', star: true, collapsedGroup: true };
38	          leaves.push(col);
39	          top.push({ kind: 'band', sc, fam, term, span: 1, rowSpan: hasBand ? 2 : 1, collapsed: true });
40	        } else {
41	          const cols = window.scenarioCols(fam, term);
42	          cols.forEach((c) => leaves.push(c));
43	          top.push({ kind: 'band', sc, fam, term, span: 3 });
44	          cols.forEach((c) => bottom.push({ kind: 'sub', label: c.label, sc, star: c.star }));
45	        }
46	      } else {
47	        leaves.push(seg);
48	        top.push({ kind: 'col', col: seg, rowSpan: hasBand ? 2 : 1 });
49	      }
50	    });
51	    return { leaves, top, bottom, hasBand };
52	  }
53	
54	  function StatusPill({ v }) {
55	    const map = {
56	      Active:   { c: RFQ.good, bg: RFQ.goodBg },
57	      Draft:    { c: RFQ.warn, bg: RFQ.warnBg },
58	      Inactive: { c: RFQ.ink3, bg: '#eef1f5' },
59	    };
60	    const s = map[v] || map.Inactive;
61	    return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, padding: '2px 8px', borderRadius: 20, background: s.bg, color: s.c, fontSize: 11, fontWeight: 600, lineHeight: 1.4 }}>
62	      <span style={{ width: 5, height: 5, borderRadius: 5, background: s.c }} />{v}
63	    </span>;
64	  }
65	
66	  function StepPill({ v }) {
67	    const st = STEPS.find((s) => s.key === v) || { short: v, color: RFQ.ink3 };
68	    return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, fontSize: 11.5, fontWeight: 500, color: RFQ.ink2 }}>
69	      <span style={{ width: 6, height: 6, borderRadius: 6, background: st.color, flex: 'none' }} />{st.short}
70	    </span>;
71	  }
72	
73	  function cellContent(col, row) {
74	    const v = row[col.key];
75	    switch (col.type) {
76	      case 'thumb':  return <Thumb hue={row.hue} size={30} />;
77	      case 'code':   return <span style={{ fontFamily: RFQ.mono, fontSize: 11.5, color: RFQ.ink2, fontWeight: 500 }}>{v}</span>;
78	      case 'money':  return money(v);
79	      case 'pct':    return pct(v);
80	      case 'qty':    return qty(v);
81	      case 'num':    return v;
82	      case 'status': return <StatusPill v={v} />;
83	      case 'step':   return <StepPill v={v} />;
84	      default:       return v;
85	    }
86	  }
87	
88	  function RfqGrid({
89	    segments, rows = window.RFQ_ROWS, density = 'comfortable', variant = 'polished',
90	    frozen = true, highlightId = null, groupRows = false, scrollLeft = 0,
91	    width = 1200, maxRows = 99, fade = true, seam = true, expandedId = null,
92	    expandedIds = [], onRowToggle = null, selectedId = null, onRowSelect = null,
93	    onGroupClick = null, onHeaderClick = null, sortKey = null, sortDir = 1, fill = false,
94	  }) {
95	    const { leaves, top, bottom, hasBand } = flatten(segments);
96	    const scrollRef = React.useRef(null);
97	    React.useLayoutEffect(() => { if (scrollRef.current) scrollRef.current.scrollLeft = scrollLeft; }, [scrollLeft]);
98	
99	    const DMAP = {
100	      compact:     { rowH: 28, fs: 12,   headH: 28, band: 22, group: 26 },
101	      standard:    { rowH: 34, fs: 12.5, headH: 30, band: 23, group: 28 },
102	      comfortable: { rowH: 40, fs: 13,   headH: 32, band: 24, group: 30 },
103	    };
104	    const D = DMAP[density] || DMAP.comfortable;
105	    const rowH = D.rowH, fs = D.fs, headH = D.headH;
106	    const pinned = frozen ? leaves.filter((c) => c.pin) : [];
107	    // left offsets for pinned leaves
108	    const offs = {}; let acc = 0;
109	    pinned.forEach((c) => { offs[c.key] = acc; acc += c.w; });
110	    const totalW = leaves.reduce((a, c) => a + c.w, 0);
111	
112	    const polished = variant === 'polished';
113	    const data = rows.slice(0, maxRows);
114	    const expanded = new Set(expandedIds);
115	    if (expandedId) expanded.add(expandedId);
116	
117	    // group rows: build ordered list with group separators
118	    let display = data;
119	    if (groupRows) {
120	      const byG = {}; const order = [];
121	      data.forEach((r) => { if (!byG[r.group]) { byG[r.group] = []; order.push(r.group); } byG[r.group].push(r); });
122	      display = [];
123	      order.forEach((g) => { display.push({ __group: g, count: byG[g].length }); byG[g].forEach((r) => display.push(r)); });
124	    }
125	
126	    const headerBg = polished ? '#f7f9fc' : RFQ.pinkSoft;
127	    const headerColor = polished ? RFQ.ink2 : RFQ.pink;
128	    const gridLine = polished ? RFQ.borderSoft : RFQ.border;
129	
130	    const th = (label, opts = {}) => (
131	      <th key={opts.k} colSpan={opts.span} rowSpan={opts.rowSpan}
132	        onClick={opts.onClick}
133	        className={opts.pin ? 'rg-pin' + (opts.shadow ? ' rg-pinshadow' : '') : ''}
134	        style={{
135	          width: opts.w, minWidth: opts.w, height: opts.h || headH, padding: '0 8px',
136	          left: opts.pin ? offs[opts.pinKey] : undefined,
137	          background: opts.bg || headerBg, color: opts.color || headerColor,
138	          fontSize: 11, fontWeight: 600, letterSpacing: '.02em',
139	          textTransform: opts.band ? 'none' : 'uppercase',
140	          textAlign: opts.align || 'left', borderBottom: `1px solid ${gridLine}`,
141	          borderRight: opts.seamEdge ? SEAM_LINE : (opts.bandEdge ? `1px solid ${opts.sc?.bandHd}` : 'none'),
142	          verticalAlign: 'middle', zIndex: opts.pin ? 5 : 1, position: opts.pin ? 'sticky' : 'static',
143	          cursor: opts.onClick ? 'pointer' : 'default', userSelect: 'none',
144	        }}>{label}</th>
145	    );
146	    const Chevron = ({ open, color }) => (
147	      <svg width="9" height="9" viewBox="0 0 10 10" style={{ transform: open ? 'rotate(90deg)' : 'none', transition: 'transform .15s', flex: 'none' }}>
148	        <path d="M3 1l5 4-5 4z" fill={color || 'currentColor'} />
149	      </svg>
150	    );
151	
152	    return (
153	      <div style={{ position: 'relative', width, fontFamily: RFQ.font }}>
154	        <div ref={scrollRef} className="rg-scroll">
155	          <table className="rg-table" style={{ width: totalW }}>
156	            <colgroup>{leaves.map((c) => <col key={c.key} style={{ width: c.w }} />)}</colgroup>
157	            <thead>
158	              <tr>
159	                {top.map((t, i) => {
160	                  if (t.kind === 'band') {
161	                    const fam = t.sc;
162	                    return th(
163	                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
164	                        <span style={{ width: 6, height: 6, borderRadius: 6, background: fam.dot }} />
165	                        {fam.label} · {t.term}
166	                        {onGroupClick
167	                          ? <span style={{ marginLeft: 2, color: t.sc.text, opacity: .7, display: 'inline-flex' }}><Chevron open={!t.collapsed} /></span>
168	                          : (t.collapsed ? <span style={{ opacity: .5, marginLeft: 2 }}>▸</span> : null)}
169	                      </span>,
170	                      { k: 'b' + i, span: t.span, rowSpan: t.rowSpan, band: true, sc: t.sc, bandEdge: true,
171	                        bg: t.sc.bandHd, color: t.sc.text, align: t.collapsed ? 'right' : 'center',
172	                        onClick: onGroupClick ? () => onGroupClick(t.fam, t.term) : undefined,
173	                        w: t.collapsed ? 92 : undefined });
174	                  }
175	                  const c = t.col;
176	                  const lastPin = frozen && c.pin && c.key === pinned[pinned.length - 1]?.key;
177	                  const sortable = onHeaderClick && c.type !== 'thumb';
178	                  const isSorted = sortKey === c.key;
179	                  return th(
180	                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, justifyContent: c.align === 'right' ? 'flex-end' : 'flex-start', width: '100%' }}>
181	                      {c.label}
182	                      {isSorted && <span style={{ color: RFQ.pink, fontSize: 9 }}>{sortDir > 0 ? '▲' : '▼'}</span>}
183	                    </span>, {
184	                    k: 'c' + i, rowSpan: t.rowSpan, w: c.w, align: c.align,
185	                    pin: frozen && c.pin, pinKey: c.key,
186	                    shadow: seam && lastPin, seamEdge: seam && lastPin,
187	                    onClick: sortable ? () => onHeaderClick(c.key) : undefined,
188	                  });
189	                })}
190	              </tr>
191	              {hasBand && (
192	                <tr>
193	                  {bottom.map((b, i) => th(
194	                    <span style={{ color: b.sc.text, opacity: b.star ? 1 : .8 }}>{b.label}</span>,
195	                    { k: 's' + i, h: D.band, bg: b.sc.band, align: 'right', color: b.sc.text }))}
196	                </tr>
197	              )}
198	            </thead>
199	            <tbody>
200	              {display.map((row, ri) => {
201	                if (row.__group) {
202	                  return (
203	                    <tr key={'g' + ri}>
204	                      <td colSpan={leaves.length} style={{ padding: 0, height: D.group, background: polished ? '#eef2f7' : '#f3f4f6', borderBottom: `1px solid ${gridLine}` }}>
205	                        <div style={{ position: 'sticky', left: 0, width: width, padding: '0 12px', display: 'flex', alignItems: 'center', gap: 8, height: D.group }}>
206	                          <span style={{ fontSize: 11.5, fontWeight: 700, color: RFQ.ink, letterSpacing: '.01em' }}>{row.__group}</span>
207	                          <span style={{ fontSize: 10.5, color: RFQ.ink3, background: '#fff', borderRadius: 10, padding: '1px 7px', fontWeight: 600 }}>{row.count}</span>
208	                        </div>
209	                      </td>
210	                    </tr>
211	                  );
212	                }
213	                const hi = highlightId === row.id || selectedId === row.id;
214	                const baseBg = hi ? RFQ.hover : (polished && ri % 2 ? RFQ.zebra : RFQ.surface);
215	                const lastPinKey = pinned[pinned.length - 1]?.key;
216	                const isOpen = expanded.has(row.id);
217	                const dataRow = (
218	                  <tr key={row.id} style={{ background: baseBg, cursor: onRowSelect ? 'pointer' : 'default' }}
219	                    onClick={onRowSelect ? () => onRowSelect(row.id) : undefined}>
220	                    {leaves.map((c) => {
221	                      const isPin = frozen && c.pin;
222	                      const isSales = c.metric === 'sales';
223	                      const isMargin = c.metric === 'margin';
224	                      const sc = c.fam ? SCENARIO[c.fam] : null;
225	                      let cellBg = baseBg;
226	                      if (polished && isSales) cellBg = hi ? '#ffe9f0' : '#fff4f8';
227	                      else if (polished && sc) cellBg = hi ? baseBg : sc.band;
228	                      const marginColor = isMargin ? (row[c.key] >= 45 ? RFQ.good : row[c.key] >= 35 ? RFQ.ink : RFQ.warn) : undefined;
229	                      const isLastPin = isPin && c.key === lastPinKey;
230	                      return (
231	                        <td key={c.key}
232	                          className={isPin ? 'rg-pin' + (seam && isLastPin ? ' rg-pinshadow' : '') : ''}
233	                          style={{
234	                            width: c.w, height: rowH, padding: c.type === 'thumb' ? '0' : '0 8px',
235	                            left: isPin ? offs[c.key] : undefined,
236	                            background: cellBg,
237	                            color: marginColor || (c.strong ? RFQ.ink : RFQ.ink2),
238	                            fontSize: fs, fontWeight: c.strong || isSales ? 600 : (c.key === 'desc' ? 500 : 400),
239	                            textAlign: c.align || 'left',
240	                            fontVariantNumeric: ['money', 'pct', 'qty', 'num'].includes(c.type) ? 'tabular-nums' : 'normal',
241	                            borderBottom: `1px solid ${gridLine}`,
242	                            borderRight: seam && isLastPin ? SEAM_LINE : (polished && sc ? `1px solid ${sc.band}` : 'none'),
243	                            verticalAlign: 'middle',
244	                            ...(c.type === 'thumb' ? { textAlign: 'center' } : {}),
245	                          }}>
246	                          {c.type === 'thumb'
247	                            ? <div style={{ display: 'flex', justifyContent: 'center' }}>{cellContent(c, row)}</div>
248	                            : (c.key === 'price_code' && onRowToggle
249	                              ? <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
250	                                  <span onClick={(e) => { e.stopPropagation(); onRowToggle(row.id); }}
251	                                    style={{ cursor: 'pointer', width: 16, height: 16, borderRadius: 4, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', color: isOpen ? RFQ.pink : RFQ.ink3, background: isOpen ? RFQ.pinkSoft : 'transparent' }}>
252	                                    <Chevron open={isOpen} />
253	                                  </span>
254	                                  <span style={{ fontFamily: RFQ.mono, fontSize: 11.5, color: isOpen ? RFQ.ink : RFQ.ink2, fontWeight: isOpen ? 700 : 500 }}>{row.price_code}</span>
255	                                </span>
256	                              : cellContent(c, row))}
257	                        </td>
258	                      );
259	                    })}
260	                  </tr>
261	                );
262	                if (expanded.has(row.id) && window.DetailSubGrid) {
263	                  return (
264	                    <React.Fragment key={row.id}>
265	                      {dataRow}
266	                      <tr>
267	                        <td colSpan={leaves.length} style={{ padding: 0, background: '#eef3f9', borderBottom: `1px solid ${gridLine}` }}>
268	                          <div style={{ position: 'sticky', left: 0, width: width }}>
269	                            <window.DetailSubGrid row={row} w={width} />
270	                          </div>
271	                        </td>
272	                      </tr>
273	                    </React.Fragment>
274	                  );
275	                }
276	                return dataRow;
277	              })}
278	            </tbody>
279	          </table>
280	        </div>
281	        {fade && <div style={{ position: 'absolute', top: 0, right: 0, bottom: 0, width: 40, pointerEvents: 'none', background: 'linear-gradient(90deg, rgba(255,255,255,0), rgba(255,255,255,0.9))' }} />}
282	      </div>
283	    );
284	  }
285	
286	  window.RfqGrid = RfqGrid;
287	})();
