// rfq-grid.jsx — reusable data-grid renderer for the RFQ canvas.
// Props let each artboard show a different state (current vs polished,
// density, frozen columns, collapsed/expanded scenario groups).
// Exports <RfqGrid> to window. Depends on rfq-data.jsx.

(function () {
  const { RFQ, SCENARIO, money, pct, qty, Thumb, STEPS } = window;
  const SEAM_LINE = '1.5px solid #d4dae3';

  // One-time grid CSS (rg- prefixed).
  if (!document.getElementById('rg-styles')) {
    const s = document.createElement('style');
    s.id = 'rg-styles';
    s.textContent = `
    .rg-scroll{overflow-x:auto;overflow-y:hidden;width:100%}
    .rg-table{border-collapse:separate;border-spacing:0;font-family:${RFQ.font};table-layout:fixed}
    .rg-table th,.rg-table td{box-sizing:border-box;text-align:left;overflow:hidden;white-space:nowrap;text-overflow:ellipsis}
    .rg-num{font-variant-numeric:tabular-nums;text-align:right;font-feature-settings:"tnum"}
    .rg-pin{position:sticky;background:inherit;z-index:2}
    .rg-pinshadow{box-shadow:6px 0 8px -6px rgba(20,30,50,.18)}
    `;
    document.head.appendChild(s);
  }

  // Flatten a segment list into header rows + leaf columns.
  // segment = plain col descriptor  OR  { group:{fam,term,collapsed} }
  function flatten(segments) {
    const leaves = [];
    const top = [];     // top header cells (bands / tall labels)
    const bottom = [];   // second-row header cells (scenario sub-labels)
    let hasBand = segments.some((s) => s.group && !s.group.collapsed);
    segments.forEach((seg, i) => {
      if (seg.group) {
        const { fam, term, collapsed } = seg.group;
        const sc = SCENARIO[fam];
        if (collapsed) {
          const col = { key: `${fam}_${term.toLowerCase()}_sales`, label: 'Sales', w: 92, type: 'money', align: 'right', fam, term, metric: 'sales', star: true, collapsedGroup: true };
          leaves.push(col);
          top.push({ kind: 'band', sc, fam, term, span: 1, rowSpan: hasBand ? 2 : 1, collapsed: true });
        } else {
          const cols = window.scenarioCols(fam, term);
          cols.forEach((c) => leaves.push(c));
          top.push({ kind: 'band', sc, fam, term, span: 3 });
          cols.forEach((c) => bottom.push({ kind: 'sub', label: c.label, sc, star: c.star }));
        }
      } else {
        leaves.push(seg);
        top.push({ kind: 'col', col: seg, rowSpan: hasBand ? 2 : 1 });
      }
    });
    return { leaves, top, bottom, hasBand };
  }

  function StatusPill({ v }) {
    const map = {
      Active:   { c: RFQ.good, bg: RFQ.goodBg },
      Draft:    { c: RFQ.warn, bg: RFQ.warnBg },
      Inactive: { c: RFQ.ink3, bg: '#eef1f5' },
    };
    const s = map[v] || map.Inactive;
    return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, padding: '2px 8px', borderRadius: 20, background: s.bg, color: s.c, fontSize: 11, fontWeight: 600, lineHeight: 1.4 }}>
      <span style={{ width: 5, height: 5, borderRadius: 5, background: s.c }} />{v}
    </span>;
  }

  function StepPill({ v }) {
    const st = STEPS.find((s) => s.key === v) || { short: v, color: RFQ.ink3 };
    return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, fontSize: 11.5, fontWeight: 500, color: RFQ.ink2 }}>
      <span style={{ width: 6, height: 6, borderRadius: 6, background: st.color, flex: 'none' }} />{st.short}
    </span>;
  }

  function cellContent(col, row) {
    const v = row[col.key];
    switch (col.type) {
      case 'thumb':  return <Thumb hue={row.hue} size={30} />;
      case 'code':   return <span style={{ fontFamily: RFQ.mono, fontSize: 11.5, color: RFQ.ink2, fontWeight: 500 }}>{v}</span>;
      case 'money':  return money(v);
      case 'pct':    return pct(v);
      case 'qty':    return qty(v);
      case 'num':    return v;
      case 'status': return <StatusPill v={v} />;
      case 'step':   return <StepPill v={v} />;
      default:       return v;
    }
  }

  function RfqGrid({
    segments, rows = window.RFQ_ROWS, density = 'comfortable', variant = 'polished',
    frozen = true, highlightId = null, groupRows = false, scrollLeft = 0,
    width = 1200, maxRows = 99, fade = true, seam = true, expandedId = null,
    expandedIds = [], onRowToggle = null, selectedId = null, onRowSelect = null,
    onGroupClick = null, onHeaderClick = null, sortKey = null, sortDir = 1, fill = false,
  }) {
    const { leaves, top, bottom, hasBand } = flatten(segments);
    const scrollRef = React.useRef(null);
    React.useLayoutEffect(() => { if (scrollRef.current) scrollRef.current.scrollLeft = scrollLeft; }, [scrollLeft]);

    const DMAP = {
      compact:     { rowH: 28, fs: 12,   headH: 28, band: 22, group: 26 },
      standard:    { rowH: 34, fs: 12.5, headH: 30, band: 23, group: 28 },
      comfortable: { rowH: 40, fs: 13,   headH: 32, band: 24, group: 30 },
    };
    const D = DMAP[density] || DMAP.comfortable;
    const rowH = D.rowH, fs = D.fs, headH = D.headH;
    const pinned = frozen ? leaves.filter((c) => c.pin) : [];
    // left offsets for pinned leaves
    const offs = {}; let acc = 0;
    pinned.forEach((c) => { offs[c.key] = acc; acc += c.w; });
    const totalW = leaves.reduce((a, c) => a + c.w, 0);

    const polished = variant === 'polished';
    const data = rows.slice(0, maxRows);
    const expanded = new Set(expandedIds);
    if (expandedId) expanded.add(expandedId);

    // group rows: build ordered list with group separators
    let display = data;
    if (groupRows) {
      const byG = {}; const order = [];
      data.forEach((r) => { if (!byG[r.group]) { byG[r.group] = []; order.push(r.group); } byG[r.group].push(r); });
      display = [];
      order.forEach((g) => { display.push({ __group: g, count: byG[g].length }); byG[g].forEach((r) => display.push(r)); });
    }

    const headerBg = polished ? '#f7f9fc' : RFQ.pinkSoft;
    const headerColor = polished ? RFQ.ink2 : RFQ.pink;
    const gridLine = polished ? RFQ.borderSoft : RFQ.border;

    const th = (label, opts = {}) => (
      <th key={opts.k} colSpan={opts.span} rowSpan={opts.rowSpan}
        onClick={opts.onClick}
        className={opts.pin ? 'rg-pin' + (opts.shadow ? ' rg-pinshadow' : '') : ''}
        style={{
          width: opts.w, minWidth: opts.w, height: opts.h || headH, padding: '0 8px',
          left: opts.pin ? offs[opts.pinKey] : undefined,
          background: opts.bg || headerBg, color: opts.color || headerColor,
          fontSize: 11, fontWeight: 600, letterSpacing: '.02em',
          textTransform: opts.band ? 'none' : 'uppercase',
          textAlign: opts.align || 'left', borderBottom: `1px solid ${gridLine}`,
          borderRight: opts.seamEdge ? SEAM_LINE : (opts.bandEdge ? `1px solid ${opts.sc?.bandHd}` : 'none'),
          verticalAlign: 'middle', zIndex: opts.pin ? 5 : 1, position: opts.pin ? 'sticky' : 'static',
          cursor: opts.onClick ? 'pointer' : 'default', userSelect: 'none',
        }}>{label}</th>
    );
    const Chevron = ({ open, color }) => (
      <svg width="9" height="9" viewBox="0 0 10 10" style={{ transform: open ? 'rotate(90deg)' : 'none', transition: 'transform .15s', flex: 'none' }}>
        <path d="M3 1l5 4-5 4z" fill={color || 'currentColor'} />
      </svg>
    );

    return (
      <div style={{ position: 'relative', width, fontFamily: RFQ.font }}>
        <div ref={scrollRef} className="rg-scroll">
          <table className="rg-table" style={{ width: totalW }}>
            <colgroup>{leaves.map((c) => <col key={c.key} style={{ width: c.w }} />)}</colgroup>
            <thead>
              <tr>
                {top.map((t, i) => {
                  if (t.kind === 'band') {
                    const fam = t.sc;
                    return th(
                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                        <span style={{ width: 6, height: 6, borderRadius: 6, background: fam.dot }} />
                        {fam.label} · {t.term}
                        {onGroupClick
                          ? <span style={{ marginLeft: 2, color: t.sc.text, opacity: .7, display: 'inline-flex' }}><Chevron open={!t.collapsed} /></span>
                          : (t.collapsed ? <span style={{ opacity: .5, marginLeft: 2 }}>▸</span> : null)}
                      </span>,
                      { k: 'b' + i, span: t.span, rowSpan: t.rowSpan, band: true, sc: t.sc, bandEdge: true,
                        bg: t.sc.bandHd, color: t.sc.text, align: t.collapsed ? 'right' : 'center',
                        onClick: onGroupClick ? () => onGroupClick(t.fam, t.term) : undefined,
                        w: t.collapsed ? 92 : undefined });
                  }
                  const c = t.col;
                  const lastPin = frozen && c.pin && c.key === pinned[pinned.length - 1]?.key;
                  const sortable = onHeaderClick && c.type !== 'thumb';
                  const isSorted = sortKey === c.key;
                  return th(
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, justifyContent: c.align === 'right' ? 'flex-end' : 'flex-start', width: '100%' }}>
                      {c.label}
                      {isSorted && <span style={{ color: RFQ.pink, fontSize: 9 }}>{sortDir > 0 ? '▲' : '▼'}</span>}
                    </span>, {
                    k: 'c' + i, rowSpan: t.rowSpan, w: c.w, align: c.align,
                    pin: frozen && c.pin, pinKey: c.key,
                    shadow: seam && lastPin, seamEdge: seam && lastPin,
                    onClick: sortable ? () => onHeaderClick(c.key) : undefined,
                  });
                })}
              </tr>
              {hasBand && (
                <tr>
                  {bottom.map((b, i) => th(
                    <span style={{ color: b.sc.text, opacity: b.star ? 1 : .8 }}>{b.label}</span>,
                    { k: 's' + i, h: D.band, bg: b.sc.band, align: 'right', color: b.sc.text }))}
                </tr>
              )}
            </thead>
            <tbody>
              {display.map((row, ri) => {
                if (row.__group) {
                  return (
                    <tr key={'g' + ri}>
                      <td colSpan={leaves.length} style={{ padding: 0, height: D.group, background: polished ? '#eef2f7' : '#f3f4f6', borderBottom: `1px solid ${gridLine}` }}>
                        <div style={{ position: 'sticky', left: 0, width: width, padding: '0 12px', display: 'flex', alignItems: 'center', gap: 8, height: D.group }}>
                          <span style={{ fontSize: 11.5, fontWeight: 700, color: RFQ.ink, letterSpacing: '.01em' }}>{row.__group}</span>
                          <span style={{ fontSize: 10.5, color: RFQ.ink3, background: '#fff', borderRadius: 10, padding: '1px 7px', fontWeight: 600 }}>{row.count}</span>
                        </div>
                      </td>
                    </tr>
                  );
                }
                const hi = highlightId === row.id || selectedId === row.id;
                const baseBg = hi ? RFQ.hover : (polished && ri % 2 ? RFQ.zebra : RFQ.surface);
                const lastPinKey = pinned[pinned.length - 1]?.key;
                const isOpen = expanded.has(row.id);
                const dataRow = (
                  <tr key={row.id} style={{ background: baseBg, cursor: onRowSelect ? 'pointer' : 'default' }}
                    onClick={onRowSelect ? () => onRowSelect(row.id) : undefined}>
                    {leaves.map((c) => {
                      const isPin = frozen && c.pin;
                      const isSales = c.metric === 'sales';
                      const isMargin = c.metric === 'margin';
                      const sc = c.fam ? SCENARIO[c.fam] : null;
                      let cellBg = baseBg;
                      if (polished && isSales) cellBg = hi ? '#ffe9f0' : '#fff4f8';
                      else if (polished && sc) cellBg = hi ? baseBg : sc.band;
                      const marginColor = isMargin ? (row[c.key] >= 45 ? RFQ.good : row[c.key] >= 35 ? RFQ.ink : RFQ.warn) : undefined;
                      const isLastPin = isPin && c.key === lastPinKey;
                      return (
                        <td key={c.key}
                          className={isPin ? 'rg-pin' + (seam && isLastPin ? ' rg-pinshadow' : '') : ''}
                          style={{
                            width: c.w, height: rowH, padding: c.type === 'thumb' ? '0' : '0 8px',
                            left: isPin ? offs[c.key] : undefined,
                            background: cellBg,
                            color: marginColor || (c.strong ? RFQ.ink : RFQ.ink2),
                            fontSize: fs, fontWeight: c.strong || isSales ? 600 : (c.key === 'desc' ? 500 : 400),
                            textAlign: c.align || 'left',
                            fontVariantNumeric: ['money', 'pct', 'qty', 'num'].includes(c.type) ? 'tabular-nums' : 'normal',
                            borderBottom: `1px solid ${gridLine}`,
                            borderRight: seam && isLastPin ? SEAM_LINE : (polished && sc ? `1px solid ${sc.band}` : 'none'),
                            verticalAlign: 'middle',
                            ...(c.type === 'thumb' ? { textAlign: 'center' } : {}),
                          }}>
                          {c.type === 'thumb'
                            ? <div style={{ display: 'flex', justifyContent: 'center' }}>{cellContent(c, row)}</div>
                            : (c.key === 'price_code' && onRowToggle
                              ? <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                                  <span onClick={(e) => { e.stopPropagation(); onRowToggle(row.id); }}
                                    style={{ cursor: 'pointer', width: 16, height: 16, borderRadius: 4, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', color: isOpen ? RFQ.pink : RFQ.ink3, background: isOpen ? RFQ.pinkSoft : 'transparent' }}>
                                    <Chevron open={isOpen} />
                                  </span>
                                  <span style={{ fontFamily: RFQ.mono, fontSize: 11.5, color: isOpen ? RFQ.ink : RFQ.ink2, fontWeight: isOpen ? 700 : 500 }}>{row.price_code}</span>
                                </span>
                              : cellContent(c, row))}
                        </td>
                      );
                    })}
                  </tr>
                );
                if (expanded.has(row.id) && window.DetailSubGrid) {
                  return (
                    <React.Fragment key={row.id}>
                      {dataRow}
                      <tr>
                        <td colSpan={leaves.length} style={{ padding: 0, background: '#eef3f9', borderBottom: `1px solid ${gridLine}` }}>
                          <div style={{ position: 'sticky', left: 0, width: width }}>
                            <window.DetailSubGrid row={row} w={width} />
                          </div>
                        </td>
                      </tr>
                    </React.Fragment>
                  );
                }
                return dataRow;
              })}
            </tbody>
          </table>
        </div>
        {fade && <div style={{ position: 'absolute', top: 0, right: 0, bottom: 0, width: 40, pointerEvents: 'none', background: 'linear-gradient(90deg, rgba(255,255,255,0), rgba(255,255,255,0.9))' }} />}
      </div>
    );
  }

  window.RfqGrid = RfqGrid;
})();

