// rfq-subgrid.jsx — polished master→detail vendor-quote sub-grid.
// Renders the factory quotes that expand under a master RFQ row, styled to
// match the master grid (same tokens). Mirrors detail-cell-renderer behavior:
// lowest price first, declines/0 sunk, orange re-quote flag, chosen row marked,
// barbell action toolbar. Exports <DetailSubGrid> to window. Depends on rfq-data.

(function () {
  const { RFQ, money, qty } = window;
  const QDATES = ['Mar 12', 'Mar 09', 'Feb 28', 'Mar 14', '—'];

  const Ic = ({ d, s = 15 }) => (
    <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor"
      strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{d}</svg>
  );
  const ICN = {
    add: <path d="M3 21h18M5 21V7l8-4v18M19 21V11l-6-3" />,
    link: <path d="M10 13a5 5 0 0 0 7 0l3-3a5 5 0 0 0-7-7l-1 1M14 11a5 5 0 0 0-7 0l-3 3a5 5 0 0 0 7 7l1-1" />,
    send: <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" />,
    trash: <path d="M3 6h18M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" />,
    check: <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14M22 4L12 14.01l-3-3" />,
  };

  // Fixed widths that hug content + a single flexing Note column absorbs the
  // remainder → no wasted space at any sub-grid width. (Real-repo equivalent:
  // colDef.flex on the note column, fixed widths elsewhere — see handoff.)
  const COLS = [
    { k: 'factory', label: 'Factory',  w: '220px',            align: 'left'  },
    { k: 'price',   label: 'Price',    w: '108px',            align: 'right' },
    { k: 'lead',    label: 'Lead',     w: '92px',             align: 'right' },
    { k: 'moq',     label: 'MOQ',      w: '104px',            align: 'right' },
    { k: 'loc',     label: 'Location', w: '116px',            align: 'left'  },
    { k: 'quoted',  label: 'Quoted',   w: '100px',            align: 'left'  },
    { k: 'status',  label: 'Status',   w: '128px',            align: 'left'  },
    { k: 'note',    label: 'Note',     w: 'minmax(200px,1fr)', align: 'left' },
  ];
  const TEMPLATE = COLS.map((c) => c.w).join(' ');

  function StatusChip({ kind }) {
    const m = {
      quoted:   { c: RFQ.good, bg: RFQ.goodBg, t: 'Quoted' },
      requote:  { c: RFQ.requote, bg: RFQ.requoteBg, t: '⚑ Re-quote' },
      declined: { c: RFQ.bad, bg: RFQ.badBg, t: 'Declined' },
    }[kind];
    return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, padding: '2px 9px', borderRadius: 20, background: m.bg, color: m.c, fontSize: 11, fontWeight: 600 }}>{m.t}</span>;
  }

  function DetailSubGrid({ row, w = 1180 }) {
    const quotes = row.vendors.slice();
    const priced = quotes.filter((v) => v.status !== 'declined' && v.price > 0);
    const lowest = Math.min(...priced.map((v) => v.price));
    const sorted = quotes.slice().sort((a, b) => {
      const ad = a.status === 'declined' || a.price <= 0, bd = b.status === 'declined' || b.price <= 0;
      if (ad !== bd) return ad ? 1 : -1;
      return a.price - b.price;
    });
    const chosenName = row.chosen_vendor;

    const cell = (content, align, extra = {}) => (
      <div style={{ padding: '0 10px', height: 38, display: 'flex', alignItems: 'center',
        justifyContent: align === 'right' ? 'flex-end' : 'flex-start', fontSize: 12.5,
        color: RFQ.ink2, overflow: 'hidden', whiteSpace: 'nowrap', textOverflow: 'ellipsis',
        fontVariantNumeric: 'tabular-nums', ...extra }}>{content}</div>
    );

    return (
      <div style={{ background: '#eef3f9', borderLeft: `3px solid ${RFQ.pink}`, padding: '14px 16px 16px', fontFamily: RFQ.font, boxSizing: 'border-box', width: w }}>
        {/* header */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10 }}>
          <span style={{ fontSize: 12.5, fontWeight: 700, color: RFQ.ink }}>Factory quotes</span>
          <span style={{ fontSize: 11, fontWeight: 600, color: RFQ.ink3, background: '#fff', borderRadius: 10, padding: '1px 8px' }}>{priced.length} quoted</span>
          <span style={{ fontSize: 11.5, color: RFQ.ink3 }}>· lowest {money(lowest)} · target landed {money(row.landed_cost)}</span>
        </div>

        {/* table card */}
        <div style={{ background: '#fff', borderRadius: 10, border: `1px solid ${RFQ.border}`, overflow: 'hidden' }}>
          {/* col headers */}
          <div style={{ display: 'grid', gridTemplateColumns: TEMPLATE, background: '#f7f9fc', borderBottom: `1px solid ${RFQ.borderSoft}` }}>
            {COLS.map((c) => (
              <div key={c.k} style={{ padding: '0 10px', height: 30, display: 'flex', alignItems: 'center',
                justifyContent: c.align === 'right' ? 'flex-end' : 'flex-start', fontSize: 10.5, fontWeight: 700,
                color: RFQ.ink3, textTransform: 'uppercase', letterSpacing: '.04em' }}>{c.label}</div>
            ))}
          </div>
          {/* rows */}
          {sorted.map((v, i) => {
            const declined = v.status === 'declined' || v.price <= 0;
            const isLow = !declined && v.price === lowest;
            const isChosen = v.name === chosenName;
            const kind = declined ? 'declined' : v.requote ? 'requote' : 'quoted';
            const rowBg = isChosen ? '#fff5f8' : i % 2 ? '#fbfcfd' : '#fff';
            return (
              <div key={v.name} style={{ display: 'grid', gridTemplateColumns: TEMPLATE, background: rowBg,
                borderBottom: i < sorted.length - 1 ? `1px solid ${RFQ.borderSoft}` : 'none',
                borderLeft: isChosen ? `3px solid ${RFQ.pink}` : '3px solid transparent', opacity: declined ? .6 : 1 }}>
                {cell(
                  <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, minWidth: 0 }}>
                    {isChosen && <span style={{ color: RFQ.pink, display: 'flex' }}><Ic d={ICN.check} s={14} /></span>}
                    <span style={{ fontWeight: 600, color: RFQ.ink, overflow: 'hidden', textOverflow: 'ellipsis' }}>{v.name}</span>
                  </span>, 'left')}
                {cell(
                  declined ? '—' :
                  <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                    {isLow && <span style={{ width: 6, height: 6, borderRadius: 6, background: RFQ.good }} />}
                    <span style={{ fontWeight: 700, color: v.requote ? RFQ.requote : RFQ.ink }}>{money(v.price)}</span>
                  </span>, 'right')}
                {cell(v.lead ? v.lead + 'd' : '—', 'right')}
                {cell(v.moq ? qty(v.moq) : '—', 'right')}
                {cell(v.loc, 'left')}
                {cell(QDATES[i] || '—', 'left', { color: RFQ.ink3, fontSize: 12 })}
                {cell(<StatusChip kind={kind} />, 'left')}
                {cell(v.note, 'left', { color: RFQ.ink3, fontStyle: 'italic' })}
              </div>
            );
          })}
        </div>

        {/* barbell action toolbar */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 12 }}>
          <div style={{ display: 'flex', gap: 8 }}>
            {[['add', 'Add Factory'], ['link', 'Invite (one-time link)'], ['send', 'Send Request']].map(([ic, t]) => (
              <button key={t} style={{ display: 'inline-flex', alignItems: 'center', gap: 6, height: 32, padding: '0 12px',
                borderRadius: 8, border: `1px solid ${RFQ.border}`, background: '#fff', color: RFQ.ink2,
                fontSize: 12.5, fontWeight: 500, cursor: 'pointer', fontFamily: RFQ.font }}>
                <span style={{ color: RFQ.ink3, display: 'flex' }}><Ic d={ICN[ic]} s={14} /></span>{t}
              </button>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button style={{ display: 'inline-flex', alignItems: 'center', gap: 6, height: 32, padding: '0 12px',
              borderRadius: 8, border: `1px solid ${RFQ.badBg}`, background: '#fff', color: RFQ.bad,
              fontSize: 12.5, fontWeight: 600, cursor: 'pointer', fontFamily: RFQ.font }}>
              <Ic d={ICN.trash} s={14} /> Delete Selected
            </button>
            <button style={{ display: 'inline-flex', alignItems: 'center', gap: 6, height: 32, padding: '0 14px',
              borderRadius: 8, border: 'none', background: RFQ.pink, color: '#fff',
              fontSize: 12.5, fontWeight: 600, cursor: 'pointer', boxShadow: '0 1px 2px rgba(216,27,96,.3)', fontFamily: RFQ.font }}>
              <Ic d={ICN.check} s={14} /> Choose Selected
            </button>
          </div>
        </div>
      </div>
    );
  }

  window.DetailSubGrid = DetailSubGrid;
})();

export const RFQ_DETAIL_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getColumnDefs()
};

function getColumnDefs() {
    const commonDefaults = {
        filter: false,
        cellRenderer: null,
        hide: false,
        rowDrag: false,
        rowGroup: false,
        headerName: null,
        editable: true,
        cellEditor: null,
        headerStyle: {}
    };

    const addColumn = (
        field: string,
        colId: string,
        width: number,
        overrides: any = {}
    ) => {
        const { roles, ...rest } = overrides;
        return {
            field,
            colId,
            width,
            ...commonDefaults,
            ...rest,
            ...(roles !== undefined ? { context: { roles } } : {})
        };
    };

    return [
        addColumn("Name", "name", 220, {
            pinned: "left",
            sortable: true,
            editable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price", "quote_price", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("CBM/pc", "cbm_pc", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Note", "vendor_note", 320, {
            sortable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Lead Time (days)", "lead_time", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price Terms", "price_terms", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Country", "fob_country", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Port", "fob_port", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Quote Date", "quote_date", 140, {
            hide: true,
            filter: "agDateColumnFilter",
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Submit", "submite_btn", 160, {
            hide: true,
            editable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        })
    ];
}

