onGridReady(params) {
  this.params = params;
  this.gridApi = params.api;
  window['gridApi'] = this.gridApi;    
  this.gridUISetupService.bootstrap(this.gridApi, this.destroy$);
  this.installFillHandleDoubleClickBlocker();
  this.gridApi.setGridOption('loading', true);

}




getRowHeight(params: RowHeightParams): number | undefined | null
getRowHeight(params) {
  if (params.node && params.node.detail) {
    if (window['role'] != 'vendor') {
      var offset = 80;
    } else {
      var offset = 26.4;
    }

    var allDetailRowHeight =
      params.data.Vendors.length *
      params.api.getSizesForCurrentTheme().rowHeight;
    var gridSizes = params.api.getSizesForCurrentTheme();
    return (
      allDetailRowHeight +
      ((gridSizes && gridSizes.headerHeight) || 0) +
      offset
    );
  }
};

async onCellValueChanged(params) {
  // When an admin fills in a price cell that was highlighted as requested, auto-remove the highlight
  if (window['role'] === 'admin') {
    const editedColId = params.column.colId;
    const allPriceSectionColIds = new Set(([] as string[]).concat(...Object.values(PRICE_SECTION_MAP)));
    if (
      allPriceSectionColIds.has(editedColId) &&
      Array.isArray(params.data.requested_price_cells) &&
      params.data.requested_price_cells.includes(editedColId)
    ) {
      params.data.requested_price_cells = params.data.requested_price_cells.filter(
        (c: string) => c !== editedColId
      );
    }
  }

  // Snapshot the duty rate + container price at the moment a "Price for Sales" cell is
  // populated, so the cell tooltip can show what the cost inputs were at that time.
  // Persisted as `price_sales_snapshots` via the updateRfqItem call below.
  if (PRICE_SALES_COL_IDS.includes(params.column.colId)) {
    capturePriceSalesSnapshot(
      params.data,
      params.column.colId,
      (colId: string) => this.getMasterFiledName(colId),
      new Date().toISOString(),
      params.newValue,
    );
    params.api.refreshCells({ rowNodes: [params.node], columns: [params.column.colId], force: true });
  }

  try {
    const res: any = await firstValueFrom(this.itemService.updateRfqItem(params.data));
    params.data['Date Modified'] = new Date().toISOString(),
      params.api.applyTransaction({ update: [params.data] });
    if (params.column.colId === 'status') {
      this.notifyRfqItemStatusChanged(params.newValue, params.data);
    }
  } catch (err) {
    console.error('[Rfq] data) failed:', err);
  }
}

toggleToolbarVisibility() {
  this.toolbarVisible = !this.toolbarVisible;
  this.refreshGridLayout();
}

get gridHeight(): string {
  return this.toolbarVisible ? 'calc(100vh - 170px)' : 'calc(100vh - 115px)';
}

private refreshGridLayout(): void {
  requestAnimationFrame(() => (this.gridApi as any)?.doLayout?.());
}

onCellMouseOver(params) {
  params.node.targetElementSrc = params.event.target
  params.node.tooltipDisplayValue = params.value
}

undo() {
  if (!this.gridApi) return;
  this.gridApi.undoCellEditing();
}

verifyVendorMode() {

  let url = this.router.url;
  let urlArray = url.split('/');
  if (urlArray.length >= 4) {
    let currentUrl = urlArray[urlArray.length - 3];
    window['currentUrl'] = this.currentUrl;
    if (currentUrl == 'filterd_rfq') {
      this.highlightedItem = urlArray[urlArray.length - 2];
      window['highlightedItem'] = this.highlightedItem;
      let highlightedItemArray = this.highlightedItem.split(',');
      this.filterd_rfq = 'true';
      window['filterd_rfq'] = this.filterd_rfq;
      this.highlitedRow = urlArray[urlArray.length - 1];
      this.getRowStyle = params => {
        if (!params.data) return {};
        if (this.highlitedRow == 'true' && params.node.rowIndex != 0 && params.node.rowIndex <= highlightedItemArray.length) {
          return { background: '#f4a460' };
        }
        return {};
      };
    }
  }
}

onFirstDataRendered(params) {
  this.restoreStateFromSession();
  // Default step filter runs async; row expansion must run after the model refreshes
  // or master-detail rows reopen (wrong UX — see applyRfqMasterDetailExpansionDefaults).
  this.applyDefaultStepFilter(() => {
    this.applyRfqMasterDetailExpansionDefaults(params.api);
    // One more pass next tick: AG Grid sometimes applies expansion after filter/model work.
    setTimeout(() => this.applyRfqMasterDetailExpansionDefaults(params.api), 0);
    // Guard against startup events overwriting restored filters with an empty model.
    this.canPersistGridState = true;
    this.saveStateToSession();
  }, this.getEffectiveRole());
}

/**
 * Row grouping + master-detail: expand only top-level group rows (gray headers).
 * Collapse every master row's detail panel and any deeper grouped levels.
 */
private applyRfqMasterDetailExpansionDefaults(api: GridApi): void {
  if (!api) {
    return;
  }
  api.forEachNode((node) => {
    if (node.group && node.level === 0) {
      api.setRowNodeExpanded(node, true);
    } else if (node.master) {
      api.setRowNodeExpanded(node, false);
    } else if (node.level > 0) {
      api.setRowNodeExpanded(node, false);
    }
  });
}

onCompanyCodeChange(event) {
  for (var i = 0; i < this.companyCode.length; i++) {
    if (this.companyCode[i].company_name == event.value) {
      this.divisionCode = this.companyCode[i].divisionCodes;
      this.selectedDivisionCode = this.companyCode[i].divisionCodes[0].division_name
    }
  }
}

