onGridReady(params) {
  this.gridInfo = params.api;
  var gridInfo = {
    id: this.rowId,
    api: params.api,
    columnApi: params.columnApi,
    rowData: this.rowData,
    components: this.frameworkComponents
  };
  this.masterGridApi.api.addDetailGridInfo(this.rowId, gridInfo);
  // if FOB countries are already loaded, ensure column defs include them
  if (this.fobCountries && this.fobCountries.length && this.colDefs) {
    for (let j = 0; j < this.colDefs.length; j++) {
      if (this.colDefs[j]?.colId === 'fob_country') {
        this.colDefs[j].cellEditorParams = { values: this.fobCountries };
      }
    }
    params.api.setColumnDefs(this.colDefs);
  }

  this.syncVendorDetailHeight();
}
onFirstDataRendered(params: FirstDataRenderedEvent) {
  // params.api.sizeColumnsToFit();
  // params.api.resetRowHeights();
  setTimeout(() => {
    params.api.resetRowHeights();
    if (this.columnsToAutoSize && this.columnsToAutoSize.length > 0) {
      params.api.autoSizeColumns(this.columnsToAutoSize);
    }
    this.syncVendorDetailHeight();
  }, 300);

}
private syncVendorDetailHeight(): void {
  if (this.role !== 'vendor' || !this.params?.node || !this.params?.api || !this.gridInfo) {
    return;
  }

  setTimeout(() => {
    const rowCount = Math.max(this.gridInfo.getDisplayedRowCount(), 1);
    const themeSizes = this.gridInfo.getSizesForCurrentTheme?.();
    const rowHeight = themeSizes?.rowHeight || 42;
    const headerHeight = themeSizes?.headerHeight || 48;
    const toolbarAndPadding = 130;

