toolUseResult.originalFile:
import { describe, expect, test } from '@jest/globals';
import { RFQ_DETAIL_COLUMN_HEADERS_CONFIG } from './rfq.detail.grid.config';

function colById(colId: string) {
  const col = RFQ_DETAIL_COLUMN_HEADERS_CONFIG.columnDefs.find((c: { colId?: string }) => c.colId === colId);
  expect(col).toBeDefined();
  return col as Record<string, unknown>;
}

describe('RFQ_DETAIL_COLUMN_HEADERS_CONFIG (Ag-Grid)', () => {
  const { columnDefs } = RFQ_DETAIL_COLUMN_HEADERS_CONFIG;

  test('exports columnDefs array', () => {
    expect(Array.isArray(columnDefs)).toBe(true);
    expect(columnDefs.length).toBeGreaterThan(0);
  });

  test('every column has field, colId, and roles', () => {
    for (const def of columnDefs) {
      if (!def.field) {
        throw new Error(`field missing for colId=${def.colId}`);
      }
      if (!def.colId) {
        throw new Error(`colId missing for field=${def.field}`);
      }
      expect(Array.isArray((def as { context?: { roles?: unknown } }).context?.roles)).toBe(true);
    }
  });

  test('colId values are unique', () => {
    const ids = columnDefs.map((c: { colId: string }) => c.colId);
    expect(new Set(ids).size).toBe(ids.length);
  });

  test('Name column is pinned left', () => {
    const name = colById('name');
    expect(name.pinned).toBe('left');
    expect(name.checkboxSelection).toBeUndefined();
    expect(name.sortable).toBe(true);
    expect(name.editable).toBe(true);
  });

  test('Price Terms and FOB Country use select editor', () => {
    const priceTerms = colById('price_terms');
    const fobCountry = colById('fob_country');
    expect(priceTerms.cellEditor).toBe('agSelectCellEditor');
    expect(fobCountry.cellEditor).toBe('agSelectCellEditor');
  });

  test('Note column remains non-sortable for free text', () => {
    const note = colById('vendor_note');
    expect(note.sortable).toBe(false);
  });

  test('expected hidden columns stay hidden by default', () => {
    const hiddenIds = ['quote_date', 'submite_btn'];
    for (const id of hiddenIds) {
      const hide = colById(id).hide;
      if (hide !== true) {
        throw new Error(`expected colId "${id}" to have hide: true, got ${String(hide)}`);
      }
    }
  });

  test('column count matches detail grid definition (catch accidental drops)', () => {
    expect(columnDefs.length).toBe(10);
  });
});

