/** Reads the persisted density, falling back to 'standard' for missing/invalid values. */
private readStoredDensity(): RfqDensity {
  let stored: string | null = null;
  try {
    stored = localStorage.getItem(RFQ_DENSITY_STORAGE_KEY);
  } catch {
    stored = null;
  }
  return stored && stored in RFQ_DENSITY ? (stored as RfqDensity) : 'standard';
}

/** Applies a density to the grid (row + header heights). Does not persist. */
private applyDensity(key: RfqDensity): void {
  if (!RFQ_DENSITY[key]) return;
  this.density = key;
  const d = RFQ_DENSITY[key];
  if (!this.gridApi || this.gridApi.isDestroyed?.()) return;
  this.gridApi.setGridOption('rowHeight', d.rowHeight);
  this.gridApi.setGridOption('headerHeight', d.headerHeight);
  this.gridApi.resetRowHeights();
}

/** Toolbar handler: change row density and persist the choice per user. */
setDensity(key: RfqDensity): void {
  if (!RFQ_DENSITY[key]) return;
  this.applyDensity(key);
