.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.toolbar-spacer {
  flex: 1 1 auto;
}

.admin-group, .filter-group, .view-group, .utility-group, .bulk-status-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- Input & Field Styling --- */

.compact-field {
  width: 150px;
}

.wide-field {
  width: 180px;
}

.bulk-status-field {
  width: 135px;
}

/* Override Mat-Field to look like a box */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  background-color: #fff !important;
}

/* Center the select value text vertically within the form field */
::ng-deep .toolbar-field {
  .mat-mdc-form-field-infix {
    display: flex;
    align-items: center;
    min-height: 40px;
  }

  .mat-mdc-select {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }

  .mat-mdc-select-value {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }
}

