.density-toggle {
  height: 36px;
  border-radius: 8px;
  overflow: hidden;

  ::ng-deep .mat-button-toggle {
    .mat-button-toggle-button {
      height: 36px;
    }
    .mat-button-toggle-label-content {
      line-height: 36px;
      padding: 0 10px;
      display: flex;
      align-items: center;
    }
    mat-icon {
      font-size: 18px;
      width: 18px;
      height: 18px;
    }
  }

  ::ng-deep .mat-button-toggle-checked {
    background-color: #fce4ec; /* brand pink-soft: marks the active density */
    color: #d81b60;
  }
}

