test('suppressNoRowsOverlay is false', () => {
  expect(createRfq().gridOptions.suppressNoRowsOverlay).toBe(false);
});

describe('density toggle', () => {
  function mockGridApi() {
    return {
      setGridOption: jest.fn(),
      resetRowHeights: jest.fn(),
      isDestroyed: () => false,
    } as any;
  }

  test('defaults to standard', () => {
    localStorage.clear();
    expect(createRfq().density).toBe('standard');
    expect(createRfq().densityOptions).toEqual(['compact', 'standard', 'comfortable']);
  });

  test('readStoredDensity returns a valid persisted value', () => {
    localStorage.setItem(RFQ_DENSITY_STORAGE_KEY, 'comfortable');
    expect((createRfq() as any).readStoredDensity()).toBe('comfortable');
  });

  test('readStoredDensity falls back to standard for missing/invalid values', () => {
    localStorage.clear();
    expect((createRfq() as any).readStoredDensity()).toBe('standard');
    localStorage.setItem(RFQ_DENSITY_STORAGE_KEY, 'gigantic');
    expect((createRfq() as any).readStoredDensity()).toBe('standard');
  });

  test('setDensity applies row + header heights and resets row heights', () => {
    localStorage.clear();
    const comp = createRfq();
    comp.gridApi = mockGridApi();
    comp.setDensity('compact');
    expect(comp.density).toBe('compact');
    expect(comp.gridApi.setGridOption).toHaveBeenCalledWith('rowHeight', RFQ_DENSITY.compact.rowHeight);
    expect(comp.gridApi.setGridOption).toHaveBeenCalledWith('headerHeight', RFQ_DENSITY.compact.headerHeight);
    expect(comp.gridApi.resetRowHeights).toHaveBeenCalled();
  });

  test('setDensity persists the choice', () => {
    localStorage.clear();
    const comp = createRfq();
    comp.gridApi = mockGridApi();
    comp.setDensity('comfortable');
    expect(localStorage.getItem(RFQ_DENSITY_STORAGE_KEY)).toBe('comfortable');
  });

  test('setDensity ignores an invalid key (no change, no persist)', () => {
    localStorage.clear();
    const comp = createRfq();
    comp.gridApi = mockGridApi();
    comp.setDensity('huge' as any);
    expect(comp.density).toBe('standard');
    expect(comp.gridApi.setGridOption).not.toHaveBeenCalled();
    expect(localStorage.getItem(RFQ_DENSITY_STORAGE_KEY)).toBeNull();
  });
});

