diff --git a/src/app/pages/rfq/rfq.component.ts b/src/app/pages/rfq/rfq.component.ts
index 290ed87b..d1ec0d9c 100644
--- a/src/app/pages/rfq/rfq.component.ts
+++ b/src/app/pages/rfq/rfq.component.ts
@@ -66,6 +66,19 @@ const PRICE_SECTION_MAP: Record<string, string[]> = {
   lic_mddp: ['lic_mddp_sell_price', 'lic_mddp_margin', 'lic_mddp_royalty', 'lic_mddp_price_sales'],
 };

+/**
+ * Density presets for the RFQ master grid (row + header heights), persisted per user.
+ * headerHeight is best-effort: defaultColDef.autoHeaderHeight lets wrapped headers grow,
+ * so rowHeight is the reliable lever. See design handoff §2.
+ */
+export const RFQ_DENSITY = {
+  compact:     { rowHeight: 30, headerHeight: 30 },
+  standard:    { rowHeight: 36, headerHeight: 32 },
+  comfortable: { rowHeight: 44, headerHeight: 36 },
+} as const;
+export type RfqDensity = keyof typeof RFQ_DENSITY;
+export const RFQ_DENSITY_STORAGE_KEY = 'rfq:density';
+
 @Component({
     selector: 'app-rfq',
     templateUrl: './rfq.component.html',
@@ -145,6 +158,10 @@ export class RfqComponent implements OnInit, OnDestroy {
   };
   toolbarVisible = true

+  // Density toggle (Compact / Standard / Comfortable), persisted per user.
+  densityOptions: RfqDensity[] = ['compact', 'standard', 'comfortable'];
+  density: RfqDensity = 'standard';
+
   groupDisplayType = 'groupRows';
   cbmOptions: any = []
   isExporting = false;
@@ -3831,10 +3848,44 @@ export class RfqComponent implements OnInit, OnDestroy {
     window['gridApi'] = this.gridApi;    
     this.gridUISetupService.bootstrap(this.gridApi, this.destroy$);
     this.installFillHandleDoubleClickBlocker();
+    this.applyDensity(this.readStoredDensity());
     this.gridApi.setGridOption('loading', true);

   }

+  /** Reads the persisted density, falling back to 'standard' for missing/invalid values. */
+  private readStoredDensity(): RfqDensity {
+    let stored: string | null = null;
+    try {
+      stored = localStorage.getItem(RFQ_DENSITY_STORAGE_KEY);
+    } catch {
+      stored = null;
+    }
+    return stored && stored in RFQ_DENSITY ? (stored as RfqDensity) : 'standard';
+  }
+
+  /** Applies a density to the grid (row + header heights). Does not persist. */
+  private applyDensity(key: RfqDensity): void {
+    if (!RFQ_DENSITY[key]) return;
+    this.density = key;
+    const d = RFQ_DENSITY[key];
+    if (!this.gridApi || this.gridApi.isDestroyed?.()) return;
+    this.gridApi.setGridOption('rowHeight', d.rowHeight);
+    this.gridApi.setGridOption('headerHeight', d.headerHeight);
+    this.gridApi.resetRowHeights();
+  }
+
+  /** Toolbar handler: change row density and persist the choice per user. */
+  setDensity(key: RfqDensity): void {
+    if (!RFQ_DENSITY[key]) return;
+    this.applyDensity(key);
+    try {
+      localStorage.setItem(RFQ_DENSITY_STORAGE_KEY, key);
+    } catch {
+      // Ignore storage failures (e.g. private mode); density still applies for the session.
+    }
+  }
+



