export type RfqDensity = keyof typeof RFQ_DENSITY;
export const RFQ_DENSITY_STORAGE_KEY = 'rfq:density';

// --- Collapsible pricing scenario column groups (handoff §1) ---
const SCENARIO_FAM_LABELS: Record<string, string> = { gen: 'General', lic: 'Licensed' };
const SCENARIO_TERM_LABELS: Record<string, string> = { fob: 'FOB', poe: 'POE', whse: 'WHSE', mddp: 'MDDP' };
/** Families × terms that get a collapsible group; also drives the expand/collapse-all helper. */
export const SCENARIO_FAMILIES = ['gen', 'lic'] as const;
export const SCENARIO_TERMS = ['fob', 'poe', 'whse', 'mddp'] as const;
/** Leaf order inside an expanded group: Price for Sales (always visible) first. */
const SCENARIO_METRIC_ORDER = ['price_sales', 'sell_price', 'margin', 'royalty'];

function scenarioMetricOf(colId: string): string | null {
  if (colId.endsWith('_price_sales')) return 'price_sales';
  if (colId.endsWith('_sell_price')) return 'sell_price';
  if (colId.endsWith('_margin')) return 'margin';
  if (colId.endsWith('_royalty')) return 'royalty';
  return null;
}

function scenarioKeyOf(colId: string): { fam: string; term: string } | null {
  const m = /^(gen|lic)_(fob|poe|whse|mddp)_/.exec(colId);
  return m ? { fam: m[1], term: m[2] } : null;
}

/** AG-Grid groupId for a scenario family/term (matches the `group-header-{fam}-{term}` class). */
export function scenarioGroupId(fam: string, term: string): string {
  return `${fam}_${term}`;
}

/**
 * Wrap the flat scenario leaf columns (Gen/Lic × FOB/POE/WHSE/MDDP) into collapsible
 * AG-Grid column groups. Each group's "Price for Sales" leaf is always visible; Sell /
 * Margin / Royalty show only when the group is expanded (`columnGroupShow: 'open'`), so the
 * grid starts calm and collapses the pricing block down to 8 visible columns. Non-scenario
 * columns keep their position. Leaf defs are cloned (only `columnGroupShow` added) so the
 * source flat colHeaders used by getMasterFiledName stay a flat, unchanged array.
 */
export function buildRfqScenarioColumnGroups(defs: any[]): any[] {
  const result: any[] = [];
  const order: string[] = [];
  const buckets: Record<string, any[]> = {};
  let insertAt = -1;

  defs.forEach((def) => {
    const colId = def?.colId;
    const key = colId ? scenarioKeyOf(colId) : null;
    const metric = colId ? scenarioMetricOf(colId) : null;
    if (!key || !metric) {
      result.push(def);
      return;
    }
    const groupId = scenarioGroupId(key.fam, key.term);
    if (!buckets[groupId]) {
      buckets[groupId] = [];
      order.push(groupId);
    }
    buckets[groupId].push({ ...def, columnGroupShow: metric === 'price_sales' ? undefined : 'open' });
    if (insertAt === -1) {
      insertAt = result.length;
      result.push(null); // placeholder; replaced with the built groups below
    }
  });

  if (insertAt === -1) {
    return result; // no scenario columns survived (e.g. role-filtered out)
  }

  const groups = order.map((groupId) => {
    const [fam, term] = groupId.split('_');
    const children = buckets[groupId].sort(
      (a, b) =>
        SCENARIO_METRIC_ORDER.indexOf(scenarioMetricOf(a.colId)!) -
        SCENARIO_METRIC_ORDER.indexOf(scenarioMetricOf(b.colId)!),
    );
    return {
      headerName: `${SCENARIO_FAM_LABELS[fam]} · ${SCENARIO_TERM_LABELS[term]}`,
      groupId,
      marryChildren: true, // keep a family together; users can't drag Sell out of its group
      headerClass: `group-header-${fam}-${term}`,
      children,
    };
  });

  result.splice(insertAt, 1, ...groups);
  return result;
}

