describe('buildRfqScenarioColumnGroups', () => {
  function sampleDefs() {
    return [
      { colId: 'price_code', field: 'Price Code' },
      { colId: 'desc', field: 'Description' },
      { colId: 'gen_fob_sell_price', field: 'Gen FOB Sell Price' },
      { colId: 'gen_fob_margin', field: 'Gen FOB Margin %' },
      { colId: 'gen_fob_price_sales', field: 'Gen FOB Price for Sales' },
      { colId: 'lic_fob_royalty', field: 'Lic FOB Royalty %' },
      { colId: 'lic_fob_sell_price', field: 'Lic FOB Sell Price' },
      { colId: 'lic_fob_margin', field: 'Lic FOB Margin %' },
      { colId: 'lic_fob_price_sales', field: 'Lic FOB Price for Sales' },
      { colId: 'note', field: 'Notes' },
    ];
  }

  test('scenarioGroupId joins family and term', () => {
    expect(scenarioGroupId('gen', 'fob')).toBe('gen_fob');
    expect(scenarioGroupId('lic', 'mddp')).toBe('lic_mddp');
  });

  test('wraps scenario leaves into groups and preserves non-scenario columns in place', () => {
    const result = buildRfqScenarioColumnGroups(sampleDefs());
    // price_code, desc, [gen_fob group], [lic_fob group], note
    expect(result).toHaveLength(5);
    expect(result[0].colId).toBe('price_code');
    expect(result[1].colId).toBe('desc');
    expect(result[result.length - 1].colId).toBe('note');
    expect(result[2].groupId).toBe('gen_fob');
    expect(result[3].groupId).toBe('lic_fob');
  });

  test('group def carries label, marryChildren, and the family headerClass', () => {
    const gen = buildRfqScenarioColumnGroups(sampleDefs())[2];
    expect(gen.headerName).toBe('General · FOB');
    expect(gen.marryChildren).toBe(true);
    expect(gen.headerClass).toBe('group-header-gen-fob');
  });

  test('Price for Sales is always visible; Sell/Margin/Royalty show only when open', () => {
    const lic = buildRfqScenarioColumnGroups(sampleDefs())[3];
    // Price for Sales leads and is always visible (undefined columnGroupShow).
    expect(lic.children[0].colId).toBe('lic_fob_price_sales');
    expect(lic.children[0].columnGroupShow).toBeUndefined();
    for (const child of lic.children.slice(1)) {
      expect(child.columnGroupShow).toBe('open');
    }
    // Royalty rides along as an open child (licensed only).
    expect(lic.children.map((c: any) => c.colId)).toContain('lic_fob_royalty');
  });

  test('does not mutate the source leaf defs (colHeaders stay flat/unchanged)', () => {
    const defs = sampleDefs();
    buildRfqScenarioColumnGroups(defs);
    expect(defs[2].colId).toBe('gen_fob_sell_price');
    expect((defs[2] as any).columnGroupShow).toBeUndefined();
    expect(defs).toHaveLength(10);
  });

  test('role-filtered input with only Price for Sales yields single-child groups', () => {
    const defs = [
      { colId: 'desc', field: 'Description' },
      { colId: 'gen_fob_price_sales', field: 'Gen FOB Price for Sales' },
      { colId: 'lic_fob_price_sales', field: 'Lic FOB Price for Sales' },
    ];
    const result = buildRfqScenarioColumnGroups(defs);
    expect(result).toHaveLength(3); // desc + 2 single-child groups
    expect(result[1].groupId).toBe('gen_fob');
    expect(result[1].children).toHaveLength(1);
    expect(result[1].children[0].columnGroupShow).toBeUndefined();
  });

  test('returns columns unchanged when there are no scenario columns', () => {
    const defs = [{ colId: 'price_code', field: 'Price Code' }, { colId: 'note', field: 'Notes' }];
    const result = buildRfqScenarioColumnGroups(defs);
    expect(result).toHaveLength(2);
    expect(result.every((c: any) => c.children === undefined)).toBe(true);
  });
});

