     selector: 'app-rfq',
     templateUrl: './rfq.component.html',
@@ -162,6 +247,9 @@ export class RfqComponent implements OnInit, OnDestroy {
   densityOptions: RfqDensity[] = ['compact', 'standard', 'comfortable'];
   density: RfqDensity = 'standard';

