-        this.columnDefs = this.applyAutoFormatters(this.colHeaders);
+        // colHeaders stays flat (getMasterFiledName depends on it); only the grid's
+        // columnDefs get the collapsible scenario groups layered on top.
+        this.columnDefs = buildRfqScenarioColumnGroups(this.applyAutoFormatters(this.colHeaders));

         window['params'] = this.params;

@@ -3886,6 +3976,21 @@ export class RfqComponent implements OnInit, OnDestroy {
     }
   }

+  /** Toolbar handler: expand or collapse every pricing scenario column group at once. */
+  togglePricingGroups(): void {
+    this.pricingExpanded = !this.pricingExpanded;
+    this.setAllPricingGroups(this.pricingExpanded);
+  }
+
+  private setAllPricingGroups(open: boolean): void {
+    if (!this.gridApi || this.gridApi.isDestroyed?.()) return;
+    for (const fam of SCENARIO_FAMILIES) {
+      for (const term of SCENARIO_TERMS) {
+        this.gridApi.setColumnGroupOpened(scenarioGroupId(fam, term), open);
+      }
+    }
+  }
+

