1	import { Injectable } from '@angular/core';
2	import {
3	  PublicClientApplication,
4	  Configuration,
5	  AuthenticationResult,
6	  PopupRequest,
7	} from '@azure/msal-browser';
8	import { environment } from '../../../environments/environment';
9	
10	/**
11	 * Thin wrapper around @azure/msal-browser for Azure AD SSO.
12	 *
13	 * We use the vanilla msal-browser package (not msal-angular) to avoid the
14	 * Angular-version coupling that the official msal-angular adapter brings.
15	 *
16	 * Lifecycle:
17	 *   1. Call `initialize()` once (done lazily on first `loginPopup()` call).
18	 *   2. Call `loginPopup()` to open the Microsoft login popup.
19	 *      Returns the raw Azure ID token string on success.
20	 */
21	@Injectable({ providedIn: 'root' })
22	export class AzureSsoService {
23	  private _msalInstance: PublicClientApplication | null = null;
24	  private _initPromise: Promise<void> | null = null;
25	
26	  private get msalConfig(): Configuration {
27	    return {
28	      auth: {
29	        clientId: environment.azureClientId,
30	        authority: `https://login.microsoftonline.com/${environment.azureTenantId}`,
31	        redirectUri: window.location.origin + '/login',
32	      },
33	      cache: {
34	        cacheLocation: 'sessionStorage',
35	      },
36	    };
37	  }
38	
39	  /** Lazily creates and initialises the MSAL instance (idempotent). */
40	  async initialize(): Promise<void> {
41	    if (this._initPromise) {
42	      return this._initPromise;
43	    }
44	    this._msalInstance = new PublicClientApplication(this.msalConfig);
45	    this._initPromise = this._msalInstance.initialize();
46	    return this._initPromise;
47	  }
48	
49	  /**
50	   * Opens the Microsoft login popup and returns the Azure ID token string.
51	   * Throws on cancellation or error.
52	   */
53	  async loginPopup(): Promise<string> {
54	    await this.initialize();
55	
56	    const request: PopupRequest = {
57	      scopes: ['openid', 'profile', 'email'],
58	      redirectUri: window.location.origin + '/assets/auth-redirect.html',
59	    };
60	
