const Sequelize = require('sequelize');
const { QueryTypes } = Sequelize;
const { FACTORY_LIST_ATTRIBUTES, RFQ_VENDOR_LIST_ATTRIBUTES } = require('./rfqListQuery');

function schemaPrefix() {
  return process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
}

function mapFactoryRecord(factory) {
  if (!factory) return null;
  const values = factory.dataValues || factory;
  return {
    id: values.id,
    factory_name: values.factory_name,
    factory_nickname: values.factory_nickname,
    factory_status: values.factory_status,
    factory_access: values.factory_access,
    factory_country: values.factory_country,
    sort_order: values.sort_order,
  };
}

function mapRfqVendorRows(vendorRecords, priceCode, rfqItemId) {
  const rows = Array.isArray(vendorRecords) ? vendorRecords : [];
  return rows
    .slice()
    .sort((a, b) => {
      const aValues = a.dataValues || a;
      const bValues = b.dataValues || b;
      const pa = parseFloat(aValues.RFQVendor_amount);
      const pb = parseFloat(bValues.RFQVendor_amount);
      if (isNaN(pa) && isNaN(pb)) return 0;
      if (isNaN(pa)) return 1;
      if (isNaN(pb)) return -1;
      return pa - pb;
    })
    .map((row) => {
      const values = row.dataValues || row;
      const price = parseFloat(values.RFQVendor_amount);
      return {
        Price: isNaN(price) ? null : price,
        Status: values.RFQVendor_status,
        'CBM/pc': values.RFQVendor_cbm_pc,
        Note: values.RFQVendor_note,
        Vendor: mapFactoryRecord(values.Factory || row.Factory),
        carton_width: values.carton_width,
        carton_height: values.carton_height,
        carton_length: values.carton_length,
        quote_date: values.quote_date,
        requote_requested: values.requote_requested,
        req_status: values.req_status,
        priceCode,
        std_vendor_id_fk: values.std_vendor_id_fk,
        row_id: rfqItemId,
        quote_id: values.RFQVendor_id,
        'Lead Time (days)': values.lead_time,
        'Price Terms': values.price_terms,
        'FOB Country': values.fob_country,
        'FOB Port': values.fob_port,
      };
    });
}

function computeResFromVendorRecords(vendorRecords) {
  const uniqueResponded = new Set();
  const uniqueRequested = new Set();
  const rows = Array.isArray(vendorRecords) ? vendorRecords : [];

  for (const row of rows) {
    const values = row.dataValues || row;
    if (values.req_status == 1) continue;
    const factoryId = values.vendor_id_fk;
    uniqueRequested.add(factoryId);
    const price = values.RFQVendor_amount;
    if (price && !isNaN(price)) {
      uniqueResponded.add(factoryId);
    }
  }

  return `${uniqueResponded.size}/${uniqueRequested.size}`;
}

async function fetchVendorResCounts(sequelize, itemIds) {
  const map = new Map();
  if (!itemIds.length) {
    return map;
  }

  const schema = schemaPrefix();
  const rows = await sequelize.query(
    `SELECT
      v."RFQitem_id_fk" AS item_id,
      COUNT(DISTINCT v."vendor_id_fk") FILTER (
        WHERE COALESCE(v."req_status", 0) <> 1
      ) AS requested,
      COUNT(DISTINCT v."vendor_id_fk") FILTER (
        WHERE COALESCE(v."req_status", 0) <> 1
          AND v."RFQVendor_amount" IS NOT NULL
          AND TRIM(v."RFQVendor_amount") <> ''
          AND v."RFQVendor_amount" ~ '^[0-9.]+$'
      ) AS responded
    FROM ${schema}"RFQVendor" v
    WHERE v."RFQitem_id_fk" IN (:itemIds)
    GROUP BY v."RFQitem_id_fk"`,
    {
      replacements: { itemIds },
      type: QueryTypes.SELECT,
    },
  );

  for (const row of rows) {
    map.set(Number(row.item_id), `${row.responded}/${row.requested}`);
  }
  return map;
}

async function fetchChosenVendorCartons(sequelize, items) {
  const map = new Map();
  const itemIds = [];
  for (const item of items) {
    const values = item.dataValues || item;
    if (values.rfqItem_id != null && values.rfqItem_choosen_vendor != null) {
      itemIds.push(values.rfqItem_id);
    }
  }
  if (!itemIds.length) {
    return map;
  }

  const schema = schemaPrefix();
  const rows = await sequelize.query(
    `SELECT
      v."RFQitem_id_fk" AS item_id,
      v."carton_width" AS carton_width,
      v."carton_height" AS carton_height,
      v."carton_length" AS carton_length
    FROM ${schema}"RFQVendor" v
    INNER JOIN ${schema}"RFQItem" i
      ON i."rfqItem_id" = v."RFQitem_id_fk"
     AND i."rfqItem_choosen_vendor" = v."vendor_id_fk"
    WHERE i."rfqItem_id" IN (:itemIds)`,
    {
      replacements: { itemIds },
      type: QueryTypes.SELECT,
    },
  );

  for (const row of rows) {
    map.set(Number(row.item_id), {
      carton_width: row.carton_width,
      carton_height: row.carton_height,
      carton_length: row.carton_length,
    });
  }
  return map;
}

function buildRfqVendorFindOptions(sql, rfqItemId, user) {
  const where = { RFQitem_id_fk: rfqItemId };
  if (user?.role === 'vendor' && user.factory_id) {
    where.vendor_id_fk = user.factory_id;
  }
  return {
    where,
    attributes: RFQ_VENDOR_LIST_ATTRIBUTES,
    include: [{
      model: sql.Factory,
      as: 'Factory',
      required: false,
      attributes: FACTORY_LIST_ATTRIBUTES,
    }],
    order: [[Sequelize.literal('"RFQVendor_id"'), 'DESC']],
  };
}

module.exports = {
  buildRfqVendorFindOptions,
  computeResFromVendorRecords,
  fetchChosenVendorCartons,
  fetchVendorResCounts,
  mapRfqVendorRows,
};

