private loadRfqItemVendors(rowData: any): Promise<any[]> {
  const rowId = rowData?.id;
  if (!rowId) {
    return Promise.resolve(rowData?.Vendors || []);
  }
  if (rowData._vendorsLoaded && Array.isArray(rowData.Vendors)) {
    return Promise.resolve(rowData.Vendors);
  }
  const pending = this.vendorLoadPromises.get(rowId);
  if (pending) {
    return pending;
  }

  const promise = firstValueFrom(this.itemService.getRfqItemVendors(rowId))
    .then((vendors) => {
      rowData.Vendors = vendors || [];
      rowData._vendorsLoaded = true;
      this.vendorLoadPromises.delete(rowId);
      return rowData.Vendors;
    })
    .catch((err) => {
      console.error('[Rfq] getRfqItemVendors failed:', err);
      this.vendorLoadPromises.delete(rowId);
      return rowData.Vendors || [];
    });
  this.vendorLoadPromises.set(rowId, promise);
  return promise;
}

async onReminder() {
  const selectedRowData = this.gridApi.getSelectedNodes();
  const sentVendors = new Set(); // ✅ Track vendor IDs to avoid duplicates
  let sentCount = 0;

  try {
    for (let i = 0; i < selectedRowData.length; i++) {
      const rowData = selectedRowData[i].data;
      if (!rowData || !rowData.Vendors) continue;

      for (let j = 0; j < rowData.Vendors.length; j++) {
        const vendorEntry = rowData.Vendors[j];
        if (vendorEntry.req_status != null) continue;

        const vendorId = vendorEntry.Vendor?.id;

        // ✅ Skip if this vendor was already emailed
        if (sentVendors.has(vendorId)) continue;
        sentVendors.add(vendorId);

        await firstValueFrom(this.itemService
          .sendPriceReq({
            id: vendorId,
            rfqItem_priceCode: vendorEntry.priceCode,
            sendEmail: true,
          }));
        sentCount++;
      }
    }
  } catch (err) {
    console.error('Failed to send reminder', err);

