Customer.getRfqItemVendors = async (req, result) => {
  try {
    const token = req.headers.authorization;
    const user = await getUserInfo(token);
    const rfqItemId = parseInt(req.body.rfqItem_id, 10);
    if (!rfqItemId) {
      result({ message: 'rfqItem_id required' }, null);
      return;
    }

    const item = await sql.RFQItem.findOne({
      where: { rfqItem_id: rfqItemId },
      attributes: ['rfqItem_id', 'rfqItem_style_number'],
    });
    if (!item) {
      result(null, []);
      return;
    }

    const vendors = await sql.RFQVendor.findAll(
      buildRfqVendorFindOptions(sql, rfqItemId, user),
    );
    result(null, mapRfqVendorRows(
      vendors,
      item.rfqItem_style_number,
