Customer.getAllVendors = async (result) => {
  const query = {
    where: {
      [Op.and]: [
        { factory_access: 'permanent' },
        { factory_status: 'Active' }
      ]
    },
    include: [{
      model: sql.vendor,
      where: {
        vendor_access: {
          [Op.ne]: 'temporary'
        }
      },
      required: true
    }],
    order: [['sort_order', 'ASC']]
  }

  await sql.Factory.findAll(query).then(data => {
    if (data) {
      result(null, data)
    } else {
      result(null, null);
    }
  })
    .catch(err => {
      result(err, null);
    });
}

Customer.updateFactorySortOrder = async ({ orderedFactories }) => {
