() => {
  const pick = (sel) => { const el = document.querySelector(sel); if(!el) return null; const r = el.getBoundingClientRect(); const cs = getComputedStyle(el); return { h: Math.round(r.height), top: Math.round(r.top), cssHeight: cs.height, overflow: cs.overflow }; };
  const header = pick('.grid-wrapper .ag-header');
  const groupRow = pick('.grid-wrapper .ag-header-row-column-group');
  const colRow = pick('.grid-wrapper .ag-header-row-column');
  const filterRow = pick('.grid-wrapper .ag-header-row-floating-filter') || pick('.grid-wrapper .ag-header-row-column-filter');
  // sum of row heights vs container
  const rowsTotal = (groupRow?.h||0) + (colRow?.h||0) + (filterRow?.h||0);
  // is the group band text visible (not clipped)? compare group row top to header top
  return { header, groupRow, colRow, filterRow, rowsTotal, containerVsRows: header ? header.h - rowsTotal : null };
}

