input.function:
() => {
  const api = window['gridApi'];
  // consistent option heights
  api.setGridOption('groupHeaderHeight', 30);
  api.setGridOption('headerHeight', 58);
  api.setGridOption('floatingFiltersHeight', 40);
  // override the old fixed-60px hack with per-row heights that match the option slots
  let s = document.getElementById('hdr-fix'); if (s) s.remove();
  s = document.createElement('style'); s.id = 'hdr-fix';
  s.textContent = `
    .grid-wrapper .ag-header .ag-header-row-group { height:30px !important; }
    .grid-wrapper .ag-header .ag-header-row-column { height:58px !important; }
    .grid-wrapper .ag-header .ag-header-row-filter { height:40px !important; }`;
  document.head.appendChild(s);
  return new Promise(res => setTimeout(() => {
    const rows = Array.from(document.querySelectorAll('.grid-wrapper .ag-header-row')).filter(el=>el.getBoundingClientRect().height>0).map(el => { const r=el.getBoundingClientRect(); return { cls: el.className.replace('ag-header-row ',''), h: Math.round(r.height), top: Math.round(r.top) }; });
    const headerH = Math.round(document.querySelector('.grid-wrapper .ag-header').getBoundingClientRect().height);
    res({ headerH, rows });
  }, 300));
}

