input.new_string:
test('setDensity applies row height and resets row heights (header stays fixed)', () => {
  localStorage.clear();
  const comp = createRfq();
  comp.gridApi = mockGridApi();
  comp.setDensity('compact');
  expect(comp.density).toBe('compact');
  expect(comp.gridApi.setGridOption).toHaveBeenCalledWith('rowHeight', RFQ_DENSITY.compact.rowHeight);
  // Header heights are fixed in gridOptions (group/column/filter), so density must
  // NOT touch headerHeight — that would desync the rows and clip the scenario band.
  expect(comp.gridApi.setGridOption).not.toHaveBeenCalledWith('headerHeight', expect.anything());
  expect(comp.gridApi.resetRowHeights).toHaveBeenCalled();
});

