() => {
  const rows = Array.from(document.querySelectorAll('.grid-wrapper .ag-header-row'))
    .filter(el => el.getBoundingClientRect().height > 0)
    .map(el => { const r = el.getBoundingClientRect(); return { cls: el.className.replace('ag-header-row ',''), h: Math.round(r.height), top: Math.round(r.top) }; });
  // de-dupe (pinned + center render same rows): take unique by cls/top
  const seen = new Set(); const uniq = [];
  for (const r of rows) { const k = r.cls+':'+r.top; if(!seen.has(k)){seen.add(k); uniq.push(r);} }
  // check overlap: each row's bottom should equal next row's top
  uniq.sort((a,b)=>a.top-b.top);
  const overlaps = [];
  for (let i=0;i<uniq.length-1;i++){ const b=uniq[i].top+uniq[i].h; if(b>uniq[i+1].top+1) overlaps.push(`${uniq[i].cls} overlaps ${uniq[i+1].cls} by ${b-uniq[i+1].top}px`); }
  // is the band text visible?
  const bandCell = document.querySelector('.grid-wrapper .ag-header-group-cell .ag-header-group-text');
  return { headerRows: uniq, overlaps, bandText: bandCell?.textContent?.trim() || null };
}

