/* Add margin-bottom to floating filter textboxes for cleaner appearance */
::ng-deep .grid-wrapper .ag-floating-filter-input input,
::ng-deep .grid-wrapper .ag-text-field-input,
::ng-deep .grid-wrapper .ag-floating-filter-body input {
  margin-bottom: 10px !important;
}

/* Prevent detail cell renderer CSS from affecting master grid header */
::ng-deep .grid-wrapper .ag-header {
  position: relative !important;
  /* Don't set z-index here as it can interfere with context menu */
}

/* --- Frozen identity pane: seam + active-row highlight (handoff §3) --- */
/* A visible rule + shadow marks the boundary between the pinned identity columns
   (Price Code · Pic · Description) and the scrolling pricing scenarios. */
::ng-deep .grid-wrapper .ag-pinned-left-header,
::ng-deep .grid-wrapper .ag-cell.ag-cell-last-left-pinned:not(.ag-cell-range-single-cell) {
  border-right: 1.5px solid #d4dae3 !important;
  box-shadow: 6px 0 8px -6px rgba(20, 30, 50, 0.18);
}

/* Active / selected row highlight that spans the frozen seam. */
::ng-deep .grid-wrapper .ag-row.ag-row-selected,
::ng-deep .grid-wrapper .ag-row.rfq-row-active {
  background: #fff5f8 !important; /* brand pink-soft */
}

/* Let the row background show through the pinned cells on the active row. */
::ng-deep .grid-wrapper .ag-row-selected .ag-cell {
  background-color: transparent;
}

/* Ensure context menu is visible above everything */
::ng-deep .ag-menu,
::ng-deep .ag-popup-child {
  z-index: 10000 !important;
}

