  const wrap = document.querySelector('.grid-wrapper .ag-theme-alpine');
  const cs = wrap ? getComputedStyle(wrap) : null;
  const headerCell = document.querySelector('.grid-wrapper .ag-header-cell');
  const hcs = headerCell ? getComputedStyle(headerCell) : null;
  const headerText = document.querySelector('.grid-wrapper .ag-header-cell .ag-header-cell-text');
  const htcs = headerText ? getComputedStyle(headerText) : null;
  const cell = document.querySelector('.grid-wrapper .ag-cell');
  const ccs = cell ? getComputedStyle(cell) : null;
  return {
    fontFamily: cs?.getPropertyValue('--ag-font-family')?.slice(0,40),
    headerBgVar: cs?.getPropertyValue('--ag-header-background-color'),
    selectedVar: cs?.getPropertyValue('--ag-selected-row-background-color'),
    headerBgComputed: hcs?.backgroundColor,
    headerTextTransform: htcs?.textTransform,
    headerTextSize: htcs?.fontSize,
    cellTabular: ccs?.fontVariantNumeric,
  };
}

