  return new Promise(res => setTimeout(() => {
    const hc = document.querySelector('.grid-wrapper .ag-header-cell');
    const hcs = hc ? getComputedStyle(hc) : null;
    res({ headerBg: hcs?.backgroundColor });
  }, 200));
}

