/* ============================================================================
   RFQ REDESIGN — Stage 1: core grid theme (brand palette)
   Retints the legacy ag-theme-alpine via its own CSS variables so the grid
   chrome matches the design tokens without swapping the theme engine (which
   would break the pricing-grid overrides, seam, and header-height fixes).
   Tokens: ink #1a202e / ink-2 #475569 / ink-3 #7b8a9a · border #e7e9ee /
   soft #eef1f5 · brand pink #d81b60 / soft #fff5f8 · radius 8.
   ============================================================================ */
::ng-deep .grid-wrapper .ag-theme-alpine {
  --ag-font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --ag-font-size: 13px;
  --ag-foreground-color: #1a202e;
  --ag-data-color: #475569;
  --ag-secondary-foreground-color: #7b8a9a;

  --ag-header-background-color: #f7f9fc;
  --ag-header-foreground-color: #475569;
  --ag-header-column-separator-color: #eef1f5;

  --ag-border-color: #e7e9ee;
  --ag-row-border-color: #eef1f5;

  --ag-odd-row-background-color: #f8fafc;
  --ag-row-hover-color: #f1f5f9;
  --ag-selected-row-background-color: #fff5f8; /* brand pink-soft */
  --ag-range-selection-border-color: #d81b60;
  --ag-input-focus-border-color: #d81b60;

  --ag-border-radius: 8px;
  --ag-wrapper-border-radius: 8px;
}

/* Tabular figures so numeric columns align cleanly. */
::ng-deep .grid-wrapper .ag-theme-alpine .ag-cell {
  font-variant-numeric: tabular-nums;
  font-feature-settings: "tnum";
}

