() => {
  const row = document.querySelector('.grid-wrapper .ag-row');
  const lastPin = document.querySelector('.grid-wrapper .ag-cell.ag-cell-last-left-pinned');
  const groupCell = document.querySelector('.grid-wrapper .ag-header-group-cell.group-header-gen-fob');
  const hdrRows = Array.from(document.querySelectorAll('.grid-wrapper .ag-header-row')).filter(e=>e.getBoundingClientRect().height>0);
  const tops = hdrRows.map(e=>({c:e.className.replace('ag-header-row ',''),h:Math.round(e.getBoundingClientRect().height),t:Math.round(e.getBoundingClientRect().top)}));
  // overlap check
  const uniq=[];const seen=new Set();for(const r of tops){const k=r.c+r.t;if(!seen.has(k)){seen.add(k);uniq.push(r);}}
  uniq.sort((a,b)=>a.t-b.t);let overlap=false;for(let i=0;i<uniq.length-1;i++){if(uniq[i].t+uniq[i].h>uniq[i+1].t+1)overlap=true;}
  return {
    rowHeight: row ? Math.round(row.getBoundingClientRect().height) : null,
    seamBorder: lastPin ? getComputedStyle(lastPin).borderRight : null,
    scenarioTintBg: groupCell ? getComputedStyle(groupCell).backgroundColor : null,
    headerOverlap: overlap,
    headerRows: uniq,
  };
}

