input.new_string:
location / {
    try_files $uri $uri/ /index.html;
}

# SPA entry point: never long-cache it. Otherwise browsers keep running an
# old build for up to 30 days after a deploy (and break when the API moves
# on without them). "no-cache" lets the browser store it but revalidate with
# the server on every load (cheap 304s), so new deploys reach everyone
# immediately. The JS/CSS it references are content-hashed and long-cached
# below. Security headers are restated here because an add_header inside a
# location replaces the http-level ones.
location = /index.html {
    add_header X-Frame-Options SAMEORIGIN always;
    add_header X-Content-Type-Options nosniff always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Cache-Control "no-cache" always;
}

location ~* \.(png|jpg|jpeg|gif|webp|woff2)$ {
    expires 365d;
    add_header Cache-Control "public, no-transform";
}

# Content-hashed build assets (filename changes every build) — safe to cache
# long. 'html' is intentionally NOT here; index.html is handled above.
location ~* \.(js|css|pdf|swf)$ {
    expires 30d;
    add_header Cache-Control "public, no-transform";
}

